js_init:
(() => {
  const stored = localStorage.getItem('ps-theme');
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
  if (stored === 'dark' || (!stored && prefersDark)) {
    document.documentElement.dataset.theme = 'dark';
  }
})();

js_toggle:
document.querySelector('.ps-wiki-dark-toggle').addEventListener('click', () => {
  const isDark = document.documentElement.dataset.theme === 'dark';
  document.documentElement.dataset.theme = isDark ? '' : 'dark';
  localStorage.setItem('ps-theme', isDark ? 'light' : 'dark');
  btn.setAttribute('aria-pressed', String(!isDark));
  btn.setAttribute('aria-label', isDark ? 'Switch to dark mode' : 'Switch to light mode');
});
